// Group items by category/tier
const items = $json.records.map(r => r.fields);
const grouped = {};

items.forEach(item => {
  const tier = `Tier ${item.source_tier}`;
  if (!grouped[tier]) grouped[tier] = [];
  grouped[tier].push(item);
});

return { grouped, item_count: items.length, items };

// Generate briefing markdown
const data = $json;
let markdown = `# Daily Intelligence Briefing

**Date**: ${new Date().toLocaleDateString('en-CA')}
**Time**: ${new Date().toLocaleTimeString()}

`;

mardown += `## Executive Summary
`;
mardown += `Total items reviewed: ${data.item_count}

`;

Object.entries(data.grouped).forEach(([tier, items]) => {
  markdown += `### ${tier}

`;
  items.slice(0, 3).forEach(item => {
    markdown += `- **${item.title}**
  - Source: ${item.source}
  - Score: ${item.combined_score}/100
  - [Read more](${item.link})

`;
  });
});

return { markdown };

